namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New comment on your post."),
        });
    }

    /// <summary>Returns all notifications that currently exist.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > sinceId).ToList();
        }
    }

    /// <summary>
    /// Simulates an external source pushing new notifications.
    /// Called by a hosted service to keep the demo interesting.
    /// </summary>
    public void AddRandom()
    {
        string[] templates =
        [
            "Server deployment completed.",
            "Disk usage exceeded 80%.",
            "New user signed up.",
            "Backup finished successfully.",
            "Payment received.",
            "Scheduled maintenance in 1 hour.",
            "Security scan passed.",
        ];

        lock (_lock)
        {
            var msg = templates[Random.Shared.Next(templates.Length)];
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow);
    }
}

namespace BlazorNotifications.Services;

/// <summary>
/// Background service that periodically adds fake notifications so
/// the polling page has something new to discover.
/// </summary>
public class NotificationGeneratorService : BackgroundService
{
    private readonly NotificationService _notifications;

    public NotificationGeneratorService(NotificationService notifications)
    {
        _notifications = notifications;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            _notifications.AddRandom();
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorNotifications.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h3>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h3>

@if (_notifications.Count == 0)
{
    <p class="text-muted">No notifications yet.</p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications.OrderByDescending(x => x.Id))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _latestId;

    // Runs during SSR *and* when the component initializes interactively.
    // Because Blazor Server re-runs OnInitializedAsync on the interactive
    // render, we load the snapshot here so the first server-rendered HTML
    // already contains the notifications.
    protected override void OnInitialized()
    {
        _notifications = NotificationSvc.GetAll();
        _latestId = _notifications.Count > 0
            ? _notifications.Max(n => n.Id)
            : 0;
    }

    // OnAfterRender only fires in an interactive context (never during
    // static SSR), so it is the safe place to kick off the polling loop.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            var newer = NotificationSvc.GetSince(_latestId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _latestId = newer.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

